code = """import pandas as pd
import json

order_items_data = locals()['var_function-call-10212734668479018772']
cases_file_path = locals()['var_function-call-340428674529266384']

# 1. Prepare valid OrderItem IDs
valid_ids = set()
for item in order_items_data:
    raw_id = item.get('Id')
    if raw_id:
        clean_id = raw_id.strip().lstrip('#')
        valid_ids.add(clean_id)

# 2. Process Cases
with open(cases_file_path, 'r') as f:
    cases_data = json.load(f)

case_counts = {}

# Today is 2021-04-10
# Past 10 months: 2020-06-10 to 2021-04-10
start_date = pd.Timestamp('2020-06-10', tz='UTC')
end_date = pd.Timestamp('2021-04-10', tz='UTC')

for case in cases_data:
    # Check ID link
    oid = case.get('orderitemid__c')
    if not oid:
        continue
    clean_oid = oid.strip().lstrip('#')
    
    if clean_oid in valid_ids:
        # Check Date
        cdate_str = case.get('createddate')
        if not cdate_str:
            continue
        # Parse date
        try:
            cdate = pd.to_datetime(cdate_str)
            # Ensure UTC
            if cdate.tzinfo is None:
                cdate = cdate.tz_localize('UTC')
            else:
                cdate = cdate.tz_convert('UTC')
            
            if start_date <= cdate <= end_date:
                month_key = cdate.strftime('%B') # Month name
                year_month = cdate.strftime('%Y-%m') # For sorting/uniqueness check
                
                # We can store by year-month to be precise, then aggregate or check
                key = f"{year_month} ({month_key})"
                case_counts[key] = case_counts.get(key, 0) + 1
        except Exception as e:
            continue

print("__RESULT__:")
print(json.dumps(case_counts))"""

